; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@command title="Which button will you press?" cancel=true
@select text="11Ｆ" exp='tf.result = ["ラドミラの塔11Ｆ", "up"]'
@select text="10Ｆ" exp='tf.result = ["ラドミラの塔10Ｆ", "up"]'
@select text="７Ｆ" exp='tf.result = ["ラドミラの塔７Ｆ", "down"]'
@select text="６Ｆ" exp='tf.result = ["ラドミラの塔６Ｆ", "down"]'
@select text="４Ｆ" exp='tf.result = ["ラドミラの塔４Ｆ", "down"]'
@select text="No" exp='tf.result = void'
[ask]
[if exp='tf.result !== void']
	@elevator map=&'tf.result[0]' lift=&'tf.result[1]'
[endif]

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=5 y=0 way=w mode=open
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="Corridor of Change"

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@notice text="In the Corridor of Change, you should continue moving westward."

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

@notice text="In the Corridor of Change, you must continue westward without deviation and never lose your way."

[eventoff]
